import React, { useState } from 'react';
import Dashboard from './Dashboard';
import { submitManualData } from './api';

function App() {
    const [analysisData, setAnalysisData] = useState(null);
    const [isLoading, setIsLoading] = useState(false);
    const [view, setView] = useState('choice'); 
    const [error, setError] = useState(null);
    const [barcode, setBarcode] = useState('');

    const [goal, setGoal] = useState('Energy');
    const [symptoms, setSymptoms] = useState([]);

    const goals = ["Energy", "Immunity", "Cognitive Focus", "Skin Health", "Muscle Recovery", "Longevity", "Gut Health"];
    const symptomList = ["Fatigue", "Stress", "Poor Sleep", "Muscle Cramps", "Brain Fog", "Joint Pain", "Brittle Nails", "Anxiety", "Dry Eyes", "Bloating"];

    const handleBarcodeSearch = async () => {
        if (!barcode) return;
        setIsLoading(true);
        setError(null);
        try {
            const response = await fetch(`http://localhost:8000/scan-barcode/${barcode}`);
            const result = await response.json();
            if (result.status === "success") {
                setAnalysisData(result.data);
            } else {
                setError(result.message);
            }
        } catch (err) {
            setError("Could not connect to NutriGen server.");
        } finally {
            setIsLoading(false);
        }
    };

    const handleManualSubmit = async () => {
        setIsLoading(true);
        try {
            const response = await submitManualData({ goal, symptoms });
            setAnalysisData(response.data);
        } catch (err) { setError("Backend connection failed."); }
        finally { setIsLoading(false); }
    };

    return (
        <div style={styles.container}>
            <header style={styles.header}>
                <h1 style={styles.title}>NutriGen<span style={{color: '#38a169'}}>.</span></h1>
                <p style={styles.subtitle}>Smart Product Analysis & Lifestyle Coaching</p>
            </header>

            <main>
                {analysisData ? (
                    <Dashboard data={analysisData} onReset={() => {setAnalysisData(null); setView('choice'); setBarcode('');}} />
                ) : view === 'choice' ? (
                    <div style={styles.choiceGrid}>
                        <div style={styles.optionCard} onClick={() => setView('scan')}>
                            <div style={{fontSize: '2rem'}}>🔍</div>
                            <h3 style={{color: '#fff'}}>Barcode Search</h3>
                            <p style={{color: '#aaa'}}>Analyze verified product data via global database.</p>
                        </div>
                        <div style={styles.optionCard} onClick={() => setView('manual')}>
                            <div style={{fontSize: '2rem'}}>📝</div>
                            <h3 style={{color: '#fff'}}>Health Quiz</h3>
                            <p style={{color: '#aaa'}}>Get recommendations based on goals and symptoms.</p>
                        </div>
                    </div>
                ) : view === 'scan' ? (
                    <div style={styles.card}>
                        <h3 style={{color: '#fff'}}>Product Lookup</h3>
                        <p style={{color: '#aaa', marginBottom: '20px'}}>Enter the barcode (EAN/UPC) of the food item.</p>
                        <input 
                            style={styles.input} 
                            placeholder="e.g., 8901058000100" 
                            value={barcode} 
                            onChange={(e) => setBarcode(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && handleBarcodeSearch()}
                        />
                        <button onClick={handleBarcodeSearch} style={styles.btn}>
                            {isLoading ? "Searching Database..." : "Analyze Product"}
                        </button>
                        <button onClick={() => setView('choice')} style={styles.backLink}>Go Back</button>
                    </div>
                ) : (
                    <div style={styles.card}>
                        <h3 style={{color: '#fff'}}>Lifestyle Assessment</h3>
                        <div style={styles.formArea}>
                            <label style={styles.label}>Primary Goal:</label>
                            <select value={goal} onChange={(e) => setGoal(e.target.value)} style={styles.input}>
                                {goals.map(g => <option key={g} value={g}>{g}</option>)}
                            </select>
                            <label style={styles.label}>Symptoms:</label>
                            <div style={styles.tagGroup}>
                                {symptomList.map(s => (
                                    <button key={s} onClick={() => {
                                        setSymptoms(prev => prev.includes(s) ? prev.filter(i => i !== s) : [...prev, s]);
                                    }} style={symptoms.includes(s) ? styles.tagActive : styles.tag}>{s}</button>
                                ))}
                            </div>
                        </div>
                        <button onClick={handleManualSubmit} style={styles.btn}>Analyze Lifestyle</button>
                        <button onClick={() => setView('choice')} style={styles.backLink}>Go Back</button>
                    </div>
                )}
                {error && <p style={{color: '#e53e3e', marginTop: '20px'}}>{error}</p>}
            </main>
        </div>
    );
}

const styles = {
    container: { maxWidth: '900px', margin: '0 auto', padding: '50px 20px', fontFamily: 'sans-serif', textAlign: 'center', color: '#fff' },
    header: { marginBottom: '40px' },
    title: { fontSize: '2.8rem', fontWeight: '800', margin: 0 },
    subtitle: { color: '#aaa', marginTop: '10px' },
    choiceGrid: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' },
    optionCard: { padding: '40px', border: '1px solid #333', borderRadius: '24px', cursor: 'pointer', background: '#1a1a1a', transition: '0.2s' },
    card: { background: '#1a1a1a', padding: '40px', borderRadius: '24px', border: '1px solid #333' },
    formArea: { textAlign: 'left', maxWidth: '500px', margin: '0 auto' },
    label: { display: 'block', fontWeight: 'bold', margin: '20px 0 10px', color: '#cbd5e0' },
    input: { width: '100%', padding: '12px', borderRadius: '10px', border: '1px solid #333', background: '#2d2d2d', color: '#fff', boxSizing: 'border-box' },
    tagGroup: { display: 'flex', gap: '8px', flexWrap: 'wrap' },
    tag: { padding: '8px 16px', borderRadius: '20px', border: '1px solid #333', background: '#2d2d2d', color: '#ccc', cursor: 'pointer' },
    tagActive: { padding: '8px 16px', borderRadius: '20px', border: '1px solid #38a169', background: 'rgba(56, 161, 105, 0.2)', color: '#38a169' },
    btn: { background: '#38a169', color: '#fff', padding: '14px 40px', borderRadius: '12px', cursor: 'pointer', border: 'none', fontWeight: 'bold', margin: '30px auto 10px', display: 'block' },
    backLink: { background: 'none', border: 'none', color: '#718096', cursor: 'pointer', textDecoration: 'underline' }
};

export default App;
